class LinkedList {
    struct Node {
        int data;
        Node* next;
        Node(int val) : data(val), next(nullptr) {}
    };
    Node* head;
public:
    LinkedList() : head(nullptr) {}
    ~LinkedList() {
        // Intended to free all nodes
        while (head != nullptr) {
            head = head->next; // BUG: leaks memory!
        }
    }
    void insert(int val) {
        Node* n = new Node(val);
        n->next = head;
        head = n;
    }
    bool contains(int val) {
        Node* current = head;
        while (current != nullptr) {
            if (current->data = val) {
                return true;
            }
            current = current->next;
        }
        return false;
    }
};

