const cache = {};
const sideEffectArray = [];

function complexFunc(n) {
  if (cache[n] !== undefined) return cache[n];
  if (n <= 1) {
    sideEffectArray.push(n);
    return n;
  }
  const result = complexFunc(n - 1) + complexFunc(n - 2);
  sideEffectArray.push(result);
  cache[n] = result;
  return result;
}

